using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    if (m == 0 || n == 0) return 0;

    // Directions: right (0, 1), down (1, 0)
    vector<pair<int, int>> dirs = {{0, 1}, {1, 0}};

    // DP table: dp[i][j][k] represents the minimal cost to reach (i,j) at step k (0: odd, 1: even)
    // Since the step can be large, we use a priority queue instead
    vector<vector<vector<long long>>> dp(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));

    // Priority queue: (cost, i, j, step_parity)
    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<tuple<long long, int, int, int>>> pq;

