    dp[0][0][0] = (0 + 1) * (0 + 1);
    pq.emplace(dp[0][0][0], 0, 0, 0);

    while (!pq.empty()) {
        auto [cost, i, j, parity] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (parity == 0) {
            // Next step is even: must wait
            long long new_cost = cost + waitCost[i][j];
            if (new_cost < dp[i][j][1]) {
                dp[i][j][1] = new_cost;
                pq.emplace(new_cost, i, j, 1);
            }
        } else {
            // Next step is odd: can move right or down
            for (auto [di, dj] : dirs) {
                int ni = i + di;
                int nj = j + dj;
                if (ni < m && nj < n) {
                    long long enter_cost = (ni + 1) * (nj + 1);
                    long long new_cost = cost + enter_cost;
                    if (new_cost < dp[ni][nj][0]) {
                        dp[ni][nj][0] = new_cost;
                        pq.emplace(new_cost, ni, nj, 0);
                    }
                }
            }
        }
    }

    return -1; // unreachable
}

